import React from 'react';
import ProgressBar from '../components/ProgressBar';
import { formatCurrency } from '../helpers/helpers';

export default function LoansScreen({ loans, setModal, setSelectedLoan }) {
  return (
    <div className="pb-24 animate-fade-in">
      <header className="px-6 pt-12 pb-6 flex justify-between items-center bg-white sticky top-0 z-10">
        <h1 className="text-2xl font-bold text-gray-800">Loans</h1>
        <button onClick={()=>setModal('takeLoan')} className="bg-emerald-600 text-white py-2 px-4 rounded-2xl font-bold hover:bg-emerald-700 transition-colors">
          Take Loan
        </button>
      </header>

      <div className="px-6 space-y-4 mt-4">
        {loans.length === 0 && <p className="text-gray-400">No active loans. Click "Take Loan" to request one.</p>}
        {loans.map(loan => {
          const remaining = loan.totalDue - loan.repaid;
          return (
            <div key={loan.id} onClick={() => setSelectedLoan(loan)} className="bg-white p-4 rounded-2xl border border-gray-50 cursor-pointer hover:bg-gray-50 transition-colors">
              <div className="flex justify-between items-center mb-2">
                <h2 className="font-bold text-gray-800">{loan.title}</h2>
                <span className="text-gray-400 text-sm">{loan.status.toUpperCase()}</span>
              </div>
              <ProgressBar current={loan.repaid} target={loan.totalDue} color="bg-emerald-600" />
              <p className="text-gray-500 text-sm mt-2">Repaid: ${formatCurrency(loan.repaid)} / ${formatCurrency(loan.totalDue)}</p>
              <p className="text-gray-500 text-sm">Remaining: ${formatCurrency(remaining)}</p>
            </div>
          );
        })}
      </div>
    </div>
  );
}
